inline_scripts:
document.addEventListener('DOMContentLoaded', function () {
  var btn = document.getElementById('newsletter-btn');
  if (!btn) return;
  btn.addEventListener('click', function () {
    var email = document.getElementById('newsletter-email').value.trim();
    var msg = document.getElementById('newsletter-msg');
    if (!email) { msg.textContent = 'Please enter an email.'; return; }
    msg.textContent = 'Subscribing…';
    fetch('/newsletter/subscribe', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: email })
    }).then(function (r) { return r.json(); }).then(function (d) {
      msg.textContent = d.ok ? 'Subscribed!' : (d.error || 'Something went wrong.');
    }).catch(function () { msg.textContent = 'Network error — please try again.'; });
  });
});

document.addEventListener('DOMContentLoaded', function () {
  var form = document.querySelector('.field-form');
  if (!form) return;
  form.addEventListener('submit', function (e) {
    e.preventDefault();
    var msg = document.getElementById('contact-msg');
    var toggle = document.getElementById('subscribe-toggle');
    var emailInput = form.querySelector('input[name="email"]');
    var email = emailInput ? emailInput.value.trim() : '';
    if (toggle && toggle.checked && email) {
      msg.textContent = 'Subscribing…';
      fetch('/newsletter/subscribe', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: email })
      }).then(function (r) { return r.json(); }).then(function (d) {
        msg.textContent = d.ok ? 'Subscribed! Message noted.' : (d.error || 'Subscribe failed, but message noted.');
      }).catch(function () { msg.textContent = 'Network error on subscribe, but message noted.'; });
    } else {
      msg.textContent = 'Message noted — thank you!';
    }
  });
});

(function () {
  var PLAN_ID = "P-4FD61211AG849600RNGYEUHI";
  var statusEl = document.getElementById("checkout-status");

  function setStatus(message, type) {
    if (!statusEl) return;
    statusEl.textContent = message;
    statusEl.className = "checkout-status checkout-status--" + type;
  }

  if (!window.paypal || !paypal.Buttons) {
    setStatus("PayPal checkout could not load. Refresh and try again.", "error");
    return;
  }

  paypal.Buttons({
    style: {
      shape: "rect",
      color: "gold",
      layout: "vertical",
      label: "subscribe",
      tagline: false
    },
    createSubscription: function (data, actions) {
      setStatus("Redirecting to PayPal...", "pending");
      return actions.subscription.create({
        plan_id: PLAN_ID
      });
    },
    onApprove: function (data) {
      setStatus("Subscription approved. Confirmation: " + data.subscriptionID, "success");
    },
    onCancel: function () {
      setStatus("Checkout was canceled. You can try again when ready.", "error");
    },
    onError: function (err) {
      console.error("PayPal checkout error:", err);
      setStatus("A PayPal error occurred. Please try again.", "error");
    }
  }).render("#paypal-button-container").then(function () {
    setStatus("Use the PayPal button below to complete signup.", "pending");
  }).catch(function (err) {
    console.error("PayPal render error:", err);
    setStatus("Could not render the PayPal button. Please refresh.", "error");
  });
})();
